import { Component, OnInit } from '@angular/core';
import { Promoter } from '@app/shared/models';
import { PromoterService } from '../services/promoter.service';

@Component({
  selector: 'app-promoters-list',
  templateUrl: './promoters-list.component.html',
  styleUrls: ['./promoters-list.component.css']
})
export class PromotersListComponent implements OnInit {
  promoters: Promoter[] = [];
  loading = false;
  error: string | null = null;

  constructor(private promoterService: PromoterService) {}

  ngOnInit(): void {
    this.loadPromoters();
  }

  loadPromoters(): void {
    this.loading = true;
    this.error = null;
    this.promoterService.getPromoters().subscribe({
      next: (data) => {
        this.promoters = data;
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Error al cargar promotores';
        this.loading = false;
        console.error(err);
      }
    });
  }
}
<div class="table-wrapper">
  <table *ngIf="!loading">
    <thead>
      <tr>
        <th>DNI</th>
        <th>Nombre y Apellido</th>
        <th>Sede Base</th>
        <th>Email Corporativo</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let promoter of promoters">
        <td>{{ promoter.dni }}</td>
        <td>{{ promoter.nombreCompleto }}</td>
        <td>{{ promoter.sede }}</td>
        <td>{{ promoter.email }}</td>
      </tr>
    </tbody>
  </table>
  <div *ngIf="loading" class="loading">Cargando...</div>
  <div *ngIf="error" class="error">{{ error }}</div>
</div>
